    render_mode:  body.render_mode  || 'browser',
    exposants_bruts: body.exposants_bruts || null,
    _origin: 'webhook'
  }
}];

// Normalise la sortie du scraper Playwright.
// Input: { exposants: [{nom, secteur, site, stand}] } ou { error: '...' }
const raw = $input.first().json;

let exposants = [];
if (Array.isArray(raw.exposants)) {
  exposants = raw.exposants;
} else if (raw.body && Array.isArray(raw.body.exposants)) {
  exposants = raw.body.exposants;
}

const BLOCK = [
  'cookie','newsletter','privacy','subscribe','terms','policy',
  'menu','login','register','home','contact','about','faq','press',
  '404','not found','le salon','programme','infos pratiques','gdpr','rgpd'
];

const isJunk = (s) => {
  const t = String(s || '').toLowerCase().trim();
  if (t.length < 2 || t.length > 150) return true;
  return BLOCK.some(b => t === b || (t.length < 30 && t.includes(b)));
};

const seen = new Set();
const results = [];

for (const e of exposants) {
  const nom = String(e.nom || '').trim();
  if (!nom || isJunk(nom)) continue;
  const key = nom.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  results.push({
    json: {
      nom,
      secteur: String(e.secteur || '').trim(),
      site:    String(e.site    || '').trim(),
      stand:   String(e.stand   || '').trim()
    }
  });
}

console.log(`Playwright parse: ${exposants.length} raw → ${results.length} clean`);
return results;

