const d = $input.item.json;
const q = d.qualification || {};
const nomExposant = d.nom_exposant || '';
const id = nomExposant.replace(/\s+/g, '-').toLowerCase() + '-' + Date.now();

const score = parseFloat(q.score_potentiel) || 0;
const taille = q.taille_estimee || 'inconnue';

const interet = score >= 0.85 ? 'Très Fort' : score >= 0.65 ? 'Fort' : score >= 0.4 ? 'Moyen' : 'Faible';
const budget = taille === 'grande' ? 'Élevé' : taille === 'moyenne' ? 'Moyen' : taille === 'petite' ? 'Faible' : 'Inconnu';

return [{
  json: {
    source: 'auto3-lead',
    salonNom: d.nom_salon || '',
    salonLieu: d.lieu_salon || '',
    salonDates: d.date_salon || '',
    salonSecteur: 'Salon Professionnel',
    salonVisiteurs: '',
    lead: {
      id: id,
      entreprise: nomExposant,
      interet: interet,
      budget: budget,
      argumentIA: q.argument_commercial || '',
      sector: d.secteur_activite || '',
      email: d.email_enrichi || '',
      linkedin: d.linkedin_enrichi || ''
    }
  }
}];

const body = $input.first().json;

let leads = [];

if (body.body && Array.isArray(body.body.leads)) {
    leads = body.body.leads;
} else if (Array.isArray(body.leads)) {
    leads = body.leads;
} else if (Array.isArray(body.body)) {
    leads = body.body;
} else if (Array.isArray(body)) {
    leads = body;
}

if (leads.length === 0) {
    return [];
}

return leads.map(lead => ({ json: lead }));
